import { Player, Position, StoredPlayerTier } from "../types";
import { getTierFromOverall } from "../lib/playerTier";
import { normalizePlayerSeedRatings, validatePlayerRatings } from "../lib/playerRatings";
import { currentSeason2026Players } from "./players-current-2026";

interface PlayerSeed {
  name: string;
  era: string;
  teamLabel: string;
  primaryPosition: Position;
  secondaryPositions: Position[];
  overall: number;
  offense: number;
  defense: number;
  playmaking: number;
  shooting: number;
  rebounding: number;
  athleticism: number;
  intangibles: number;
  durability: number;
  archetype: string;
  hallOfFameTier: StoredPlayerTier;
  shortDescription: string;
  badges: string[];
  ballDominance: number;
  interiorDefense: number;
  perimeterDefense: number;
}

const makePlayer = (seed: PlayerSeed): Player => {
  const normalizedRatings = normalizePlayerSeedRatings(seed);

  return {
    id: seed.name.toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/^-+|-+$/g, ""),
    ...seed,
    ...normalizedRatings,
    hallOfFameTier: getTierFromOverall(seed.overall),
  };
};

